import yaml
import base64
import os

ca = """"""

cert = """"""

key = """"""

# Clean up whitespaces
def clean(s):
    return "".join(s.split())

config = {
    'apiVersion': 'v1',
    'clusters': [{
        'cluster': {
            'certificate-authority-data': clean(ca),
            'server': 'https://127.0.0.1:51935'
        },
        'name': 'docker-desktop'
    }],
    'contexts': [{
        'context': {
            'cluster': 'docker-desktop',
            'user': 'docker-desktop'
        },
        'name': 'docker-desktop'
    }],
    'current-context': 'docker-desktop',
    'kind': 'Config',
    'users': [{
        'name': 'docker-desktop',
        'user': {
            'client-certificate-data': clean(cert),
            'client-key-data': clean(key)
        }
    }]
}

path = os.path.expanduser("~/.kube/config")
with open(path, 'w', encoding='utf-8') as f:
    yaml.dump(config, f, default_flow_style=False)
print("Restored clean config")
